                {{ record.completed ? '已完成' : '未完成' }}
              </div>
            </div>
            <div class="record-details" v-if="record.exercises && record.exercises.length > 0">
              <h4 class="details-title">训练内容</h4>
              <div class="exercise-list">
                <div class="exercise-item" v-for="exercise in record.exercises" :key="exercise.id">
                  <div class="exercise-info">
                    <span class="exercise-name">{{ exercise.name }}</span>
                    <span class="exercise-sets">{{ exercise.sets }}组 × {{ exercise.reps }}次</span>
                  </div>
                  <div class="exercise-status" :class="exercise.completed ? 'completed' : ''">
                    {{ exercise.completed ? '✓' : '○' }}
                  </div>
                </div>
              </div>
            </div>
            <div class="record-footer">
              <span class="record-duration">{{ record.duration || 0 }}分钟</span>
              <button class="detail-button" @click="viewRecordDetail(record)">
                详情
              </button>
            </div>
          </div>
        </div>
        <div v-if="loading" class="loading">
          <div class="loading-spinner"></div>
          <p>加载中...</p>
        </div>
        <div v-if="!loading && records.length === 0" class="no-records">
          <p>暂无训练记录</p>
        </div>

        <!-- 分页 -->
        <div class="pagination" v-if="totalPages > 1">
          <button class="page-button" @click="changePage(1)" :disabled="currentPage === 1">
            首页
          </button>
          <button class="page-button" @click="changePage(currentPage - 1)" :disabled="currentPage === 1">
            上一页
          </button>
          <span class="page-info">
            第 {{ currentPage }} / {{ totalPages }} 页
          </span>
          <button class="page-button" @click="changePage(currentPage + 1)" :disabled="currentPage === totalPages">
            下一页
          </button>
          <button class="page-button" @click="changePage(totalPages)" :disabled="currentPage === totalPages">
            末页
          </button>
        </div>
      </div>
    </div>
  </div>
