<script setup lang="ts">
import { ref, onMounted, nextTick, computed } from 'vue';
import axios from 'axios';

interface Exercise {
  id: number;
  name: string;
  sets: number;
  reps: number;
  completed?: boolean;
}

interface TrainingRecord {
  id: number;
  planId: number;
  date: string;
  completed: boolean;
  exercises: Exercise[];
  duration?: number;
  exercisesJson?: string;
}

interface Plan {
  id: number;
  name: string;
}

const records = ref<TrainingRecord[]>([]);
const plans = ref<Plan[]>([]);
const loading = ref(true);
const currentPage = ref(1);
const totalPages = ref(1);
const pageSize = ref(10);

const filters = ref({
  planId: '',
  date: '',
  status: ''
});

const initParticles = () => {
  const particleBg = document.getElementById('particleBg');
  if (!particleBg) return;
  
  for (let i = 0; i < 15; i++) {
    const particle = document.createElement('div');
    particle.className = 'particle';
    const size = Math.random() * 25 + 8;
    particle.style.width = `${size}px`;
    particle.style.height = `${size}px`;
    particle.style.left = `${Math.random() * 100}%`;
    particle.style.top = `${Math.random() * 100}%`;
    particle.style.animationDelay = `${Math.random() * 15}s`;
    particle.style.animationDuration = `${Math.random() * 10 + 10}s`;
    
    const colors = ['#FF6B35', '#4ECDC4', '#FFD166', '#EF476F'];
    const color = colors[Math.floor(Math.random() * colors.length)];
    particle.style.background = `radial-gradient(circle, ${color}40 0%, ${color}00 70%)`;
    
    particleBg.appendChild(particle);
  }
};

const getToken = () => {
  return localStorage.getItem('token');
};

const apiClient = axios.create({
  baseURL: 'http://localhost:8080',
  headers: {
    'Content-Type': 'application/json'
  }
});

apiClient.interceptors.request.use((config) => {
  const token = getToken();
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

const fetchPlans = async () => {
  try {
    const response = await apiClient.get('/api/plan/list');
    if (response.data.code === 200 && response.data.data) {
      plans.value = response.data.data;
    }
  } catch (error) {
    console.error('获取计划列表失败:', error);
  }
};

const fetchRecords = async () => {
  try {
    loading.value = true;
    const params = {
      page: currentPage.value,
      pageSize: pageSize.value,
      planId: filters.value.planId,
      date: filters.value.date,
      status: filters.value.status
    };
    
    const response = await apiClient.get('/api/workout/records', { params });
    if (response.data.code === 200 && response.data.data) {
      records.value = response.data.data.records.map((record: any) => {
        if (record.exercisesJson) {
          record.exercises = JSON.parse(record.exercisesJson);
        }
        return record;
      });
      totalPages.value = response.data.data.totalPages;
    }
  } catch (error) {
    console.error('获取训练记录失败:', error);
  } finally {
    loading.value = false;
  }
};

const changePage = (page: number) => {
  if (page >= 1 && page <= totalPages.value) {
    currentPage.value = page;
    fetchRecords();
  }
};

const getPlanName = (planId: number): string => {
  const plan = plans.value.find(p => p.id === planId);
  return plan ? plan.name : '未知计划';
};

const formatDate = (dateString: string): string => {
  const date = new Date(dateString);
  return `${date.getFullYear()}年${date.getMonth() + 1}月${date.getDate()}日`;
};

const viewRecordDetail = (record: TrainingRecord) => {
  // 这里可以实现查看记录详情的逻辑
  console.log('查看记录详情:', record);
};

onMounted(() => {
  nextTick(() => {
    initParticles();
  });
  fetchPlans();
  fetchRecords();
});
</script>

