    transform: scale(1);
  }
  50% {
    transform: scale(1.05);
  }
}

@keyframes spin {
  0% {
    transform: rotate(0deg);
  }
  100% {
    transform: rotate(360deg);
  }
}

.animate-in {
  animation: fadeInUp 0.6s ease forwards;
}

/* 主容器 */
.records-container {
  width: 100%;
  min-height: 100vh;
  background: linear-gradient(135deg, #f5f7fa 0%, #c3cfe2 100%);
  position: relative;
  overflow: hidden;
}

/* 头部设计 */
.header {
  position: relative;
  background: linear-gradient(135deg, #FF6B35 0%, #FF8E53 100%);
  color: white;
  padding: 40rpx 20rpx;
  text-align: center;
  border-bottom-left-radius: 30rpx;
  border-bottom-right-radius: 30rpx;
  box-shadow: 0 4rpx 20rpx rgba(255, 107, 53, 0.3);
  overflow: hidden;
}

.header-bg {
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background-image: radial-gradient(circle at 20% 80%, rgba(255, 255, 255, 0.2) 0%, transparent 50%),
                    radial-gradient(circle at 80% 20%, rgba(255, 255, 255, 0.1) 0%, transparent 50%);
  animation: float 6s ease-in-out infinite;
}

@keyframes float {
  0%, 100% {
    transform: translateY(0) rotate(0deg);
  }
  50% {
    transform: translateY(-10rpx) rotate(1deg);
  }
}

.title {
  font-size: 36rpx;
  font-weight: bold;
  position: relative;
  z-index: 1;
  text-shadow: 0 2rpx 4rpx rgba(0, 0, 0, 0.1);
}

/* 内容区域 */
.content {
  padding: 30rpx 20rpx;
  padding-bottom: 160rpx;
}

/* 筛选区域 */
.filter-section {
  background: rgba(255, 255, 255, 0.95);
  backdrop-filter: blur(10px);
  border-radius: 24rpx;
  padding: 30rpx;
  margin-bottom: 25rpx;
  box-shadow: 0 8rpx 30rpx rgba(0, 0, 0, 0.08);
  position: relative;
  overflow: hidden;
}

.filter-section::before {
  content: '';
  position: absolute;
  top: 0;
  left: 0;
  right: 0;
  height: 4rpx;
  background: linear-gradient(90deg, #FF6B35, #FF8E53);
  border-top-left-radius: 24rpx;
  border-top-right-radius: 24rpx;
}

.filter-item {
  margin-bottom: 20rpx;
}

.filter-item:last-child {
  margin-bottom: 0;
}

.filter-label {
  display: block;
  font-size: 24rpx;
  font-weight: 600;
  color: #333;
  margin-bottom: 10rpx;
}

.filter-select,
.filter-input {
  width: 100%;
  padding: 15rpx;
  border: 1rpx solid #E0E0E0;
  border-radius: 12rpx;
  font-size: 24rpx;
  background: white;
  transition: all 0.3s ease;
  box-sizing: border-box;
}

.filter-select:focus,
.filter-input:focus<template>
  <div class="records-container">
    <div class="particle-bg" id="particleBg"></div>
    <div class="header">
      <h1 class="title neon-glow">锻炼记录</h1>
      <div class="header-bg"></div>
    </div>
    <div class="content">
      <!-- 筛选区域 -->
      <div class="filter-section animate-in">
        <div class="filter-item">
          <label class="filter-label">计划</label>
          <select v-model="filters.planId" class="filter-select" @change="fetchRecords">
            <option value="">全部计划</option>
            <option v-for="plan in plans" :key="plan.id" :value="plan.id">
              {{ plan.name }}
            </option>
          </select>
        </div>
        <div class="filter-item">
          <label class="filter-label">日期</label>
          <input type="date" v-model="filters.date" class="filter-input" @change="fetchRecords" />
        </div>
        <div class="filter-item">
          <label class="filter-label">状态</label>
          <select v-model="filters.status" class="filter-select" @change="fetchRecords">
            <option value="">全部状态</option>
            <option value="completed">已完成</option>
            <option value="pending">未完成</option>
          </select>
        </div>
      </div>

      <!-- 记录列表 -->
      <div class="records-section animate-in">
        <h2 class="section-title">训练记录</h2>
        <div class="record-list" v-if="records.length > 0">
          <div class="record-card" v-for="record in records" :key="record.id" :class="['record-card', 'animate-in']">
            <div class="record-header">
              <div class="record-info">
                <h3 class="record-plan">{{ getPlanName(record.planId) }}</h3>
                <p class="record-date">{{ formatDate(record.date) }}</p>
              </div>
              <div class="record-status" :class="record.completed ? 'completed' : 'pending'">
                {{ record.completed ? '已完成' : '未完成' }}
              </div>
            </div>
            <div class="record-details" v-if="record.exercises && record.exercises.length > 0">
              <h4 class="details-title">训练内容</h4>
              <div class="exercise-list">
                <div class="exercise-item" v-for="exercise in record.exercises" :key="exercise.id">
                  <div class="exercise-info">
                    <span class="exercise-name">{{ exercise.name }}</span>
                    <span class="exercise-sets">{{ exercise.sets }}组 × {{ exercise.reps }}次</span>
                  </div>
                  <div class="exercise-status" :class="exercise.completed ? 'completed' : ''">
                    {{ exercise.completed ? '✓' : '○' }}
                  </div>
                </div>
              </div>
            </div>
            <div class="record-footer">
              <span class="record-duration">{{ record.duration || 0 }}分钟</span>
              <button class="detail-button" @click="viewRecordDetail(record)">
                详情
              </button>
            </div>
          </div>
        </div>
        <div v-if="loading" class="loading">
          <div class="loading-spinner"></div>
          <p>加载中...</p>
        </div>
        <div v-if="!loading && records.length === 0" class="no-records">
          <p>暂无训练记录</p>
        </div>

        <!-- 分页 -->
        <div class="pagination" v-if="totalPages > 1">
          <button class="page-button" @click="changePage(1)" :disabled="currentPage === 1">
            首页
          </button>
          <button class="page-button" @click="changePage(currentPage - 1)" :disabled="currentPage === 1">
            上一页
          </button>
          <span class="page-info">
            第 {{ currentPage }} / {{ totalPages }} 页
          </span>
          <button class="page-button" @click="changePage(currentPage + 1)" :disabled="currentPage === totalPages">
            下一页
          </button>
          <button class="page-button" @click="changePage(totalPages)" :disabled="currentPage === totalPages">
            末页
          </button>
        </div>
      </div>
    </div>
  </div>
</template>

<script setup lang="ts">
import { ref, onMounted, nextTick, computed } from 'vue';
import axios from 'axios';

interface Exercise {
  id: number;
  name: string;
  sets: number;
  reps: number;
  completed?: boolean;
}

interface TrainingRecord {
  id: number;
  planId: number;
  date: string;
  completed: boolean;
  exercises: Exercise[];
  duration?: number;
  exercisesJson?: string;
}

interface Plan {
  id: number;
  name: string;
}

const records = ref<TrainingRecord[]>([]);
const plans = ref<Plan[]>([]);
const loading = ref(true);
const currentPage = ref(1);
const totalPages = ref(1);
const pageSize = ref(10);

const filters = ref({
  planId: '',
  date: '',
  status: ''
});

const initParticles = () => {
  const particleBg = document.getElementById('particleBg');
  if (!particleBg) return;
  
  for (let i = 0; i < 15; i++) {
    const particle = document.createElement('div');
    particle.className = 'particle';
    const size = Math.random() * 25 + 8;
    particle.style.width = `${size}px`;
    particle.style.height = `${size}px`;
    particle.style.left = `${Math.random() * 100}%`;
    particle.style.top = `${Math.random() * 100}%`;
    particle.style.animationDelay = `${Math.random() * 15}s`;
    particle.style.animationDuration = `${Math.random() * 10 + 10}s`;
    
    const colors = ['#FF6B35', '#4ECDC4', '#FFD166', '#EF476F'];
    const color = colors[Math.floor(Math.random() * colors.length)];
    particle.style.background = `radial-gradient(circle, ${color}40 0%, ${color}00 70%)`;
    
    particleBg.appendChild(particle);
  }
};

const getToken = () => {
  return localStorage.getItem('token');
};

const apiClient = axios.create({
  baseURL: 'http://localhost:8080',
  headers: {
    'Content-Type': 'application/json'
  }
});

apiClient.interceptors.request.use((config) => {
  const token = getToken();
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

const fetchPlans = async () => {
  try {
    const response = await apiClient.get('/api/plan/list');
    if (response.data.code === 200 && response.data.data) {
      plans.value = response.data.data;
    }
  } catch (error) {
    console.error('获取计划列表失败:', error);
  }
};

const fetchRecords = async () => {
  try {
    loading.value = true;
    const params = {
      page: currentPage.value,
      pageSize: pageSize.value,
      planId: filters.value.planId,
      date: filters.value.date,
      status: filters.value.status
    };
    
    const response = await apiClient.get('/api/workout/records', { params });
    if (response.data.code === 200 && response.data.data) {
      records.value = response.data.data.records.map((record: any) => {
        if (record.exercisesJson) {
          record.exercises = JSON.parse(record.exercisesJson);
        }
        return record;
      });
      totalPages.value = response.data.data.totalPages;
    }
  } catch (error) {
    console.error('获取训练记录失败:', error);
  } finally {
    loading.value = false;
  }
};

const changePage = (page: number) => {
  if (page >= 1 && page <= totalPages.value) {
    currentPage.value = page;
    fetchRecords();
  }
};

const getPlanName = (planId: number): string => {
  const plan = plans.value.find(p => p.id === planId);
  return plan ? plan.name : '未知计划';
};

const formatDate = (dateString: string): string => {
  const date = new Date(dateString);
  return `${date.getFullYear()}年${date.getMonth() + 1}月${date.getDate()}日`;
};

const viewRecordDetail = (record: TrainingRecord) => {
  // 这里可以实现查看记录详情的逻辑
  console.log('查看记录详情:', record);
};

onMounted(() => {
  nextTick(() => {
    initParticles();
  });
  fetchPlans();
  fetchRecords();
});
</script>

